INSERT INTO "songs_fts_content" VALUES(1,'s_demo_du_nai','校 胁芯褉芯褌, 胁芯褉芯褌 (袗泄, 袛褍薪邪泄 屑芯泄 袛褍薪邪泄)',replace('校 胁芯褉芯褌, 胁芯褉芯褌, 胁芯褉芯褌,\n袛邪 胁芯褉芯褌 斜邪褌褞褕泻懈薪褘褏.\n袗泄, 袛褍薪邪泄, 屑芯泄 袛褍薪邪泄,\n袗泄, 胁械褋褢谢褘泄 袛褍薪邪泄!\n\n(写邪谢褜褕械 褌械泻褋褌 锌芯 褌胁芯懈屑 写邪薪薪褘屑)','\n',char(10)));
INSERT INTO "songs_fts_content" VALUES(2,'s_demo_captains','袦褘 斜褍写械屑 泻邪锌懈褌邪薪邪屑懈',replace('袚褍谢褟褞褌 胁芯谢薪褘 斜械谢褘械,\n袩褉芯褋褌芯褉褘 褕懈褉芯泻懈.\n袙褘褏芯写褟褌 胁 屑芯褉械 褋屑械谢褘械\n袪械斜褟褌邪-屑芯褉褟泻懈.\n袠 胁械褌械褉 薪邪写 谢懈屑邪薪邪屑懈,\n袠 写褘褕懈褌褋褟 胁芯谢褜薪械泄,\n袦褘 斜褍写械屑 泻邪锌懈褌邪薪邪屑懈,\n袥褞斜懈屑褑邪屑懈 屑芯褉械泄!\n\n袩褉懈锌械胁:\n袣芯谢褘褕械褌褋褟 锌邪褉褍褋 泻褉褘谢邪褌褘泄,\n袠 褋芯谢薪褑械 斜械卸懈褌 锌芯 胁芯谢薪邪屑.\n袩芯锌褍褌薪芯谐芯 胁械褌褉邪, 褉械斜褟褌邪,\n小褔邪褋褌谢懈胁芯谐芯 锌谢邪胁邪薪褜褟 胁邪屑!\n\n小锌械褕邪 薪邪褋 胁 屑芯褉械 胁褘薪械褋褌懈,\n袘邪泄写邪褉泻邪 屑褔懈褌 胁锌械褉褢写.\n小泻芯褉械泄 斜褘 褌芯谢褜泻芯 胁褘褉邪褋褌懈 -\n小谢褍卸懈褌褜 锌芯泄写褢屑 胁芯 褎谢芯褌.\n袦芯褉褟屑懈, 芯泻械邪薪邪屑懈\n袧邪褕 泻褉邪褋薪褘泄 胁褘屑锌械谢, 褉械泄,\n袦褘 斜褍写械屑 泻邪锌懈褌邪薪邪屑懈,\n袥褞斜懈屑褑邪屑懈 屑芯褉械泄!\n\n袩褉懈锌械胁.\n\n袠 械褋谢懈 胁 芯泻械邪薪械 薪邪屑\n袩褉懈写褢褌褋褟 写褉械泄褎芯胁邪褌褜,\n袘邪写懈谐懈薪褘屑, 袩邪锌邪薪懈薪褘屑\n袥褞斜芯泄 褋褍屑械械褌 褋褌邪褌褜.\n袧懈 褕褌芯褉屑芯屑, 薪懈 褌褍屑邪薪邪屑懈\n小 写芯褉芯谐懈 薪邪褋 薪械 褋斜懈褌褜.\n袦褘 斜褍写械屑 泻邪锌懈褌邪薪邪屑懈\n袩褉芯褋褌芯褉褘 斜芯褉芯蟹写懈褌褜!\n\n袩褉懈锌械胁.','\n',char(10)));
INSERT INTO "songs_fts_content" VALUES(3,'s_demo_pockmarked','袩械褋薪褟 褉褟斜芯谐芯 锌邪褉薪褟',replace('袙 褋邪写褍 褟斜谢芯薪褟 褑胁械褌械褌,\n袩芯写 芯泻薪芯屑 写械胁懈褑邪 褕褜褢褌,\n袦薪械 褉褍斜邪褕泻褍 胁褘褕懈胁邪械褌,\n袟芯谢芯褌芯泄 褍蟹芯褉 泻谢邪写褢褌,\n袞写褢褌 屑懈谢芯谐芯, 锌芯写卸懈写邪械褌,\n袗 屑懈谢芯泄-褌芯 薪械 懈写褢褌!\n袠 胁 芯泻芯薪褑械 薪械 谐谢褟写懈褌,\n袧邪 泻褉褘谢褜褑芯 褋褌褉械谢芯泄 谢械褌懈褌.\n袪邪褋褑械谢褍褞 屑芯褞 泻褉邪谢褞,\n袧邪 褍褕泻芯 褕械锌薪褍 褋谢芯胁褑芯,\n袣褉邪褋薪褘屑 屑邪泻芯屑 蟹邪锌褘谢邪械褌,\n袟邪褉褍屑褟薪械薪薪芯 谢懈褑芯!','\n',char(10)));
